INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-board-intro','class-pre-board','64 Squares','The chess board','🗺️','preschool',15,0,'[]','[{"id":"grid","kind":"info","coach":"Chess is played on a board of 64 squares — 8 rows and 8 columns. Squares alternate light and dark colours. We always set up the board so a light square sits in the bottom-right corner from each player''s view.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","highlight":["h1","a8"],"highlightFiles":["h"],"highlightRanks":[1]},{"id":"files-intro","kind":"info","coach":"The vertical columns are called files. They are labelled a through h from left to right (White''s view). Watch the purple column light up on the a-file.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","highlight":["a1"],"highlightFiles":["a"]},{"id":"ranks-intro","kind":"info","coach":"The horizontal rows are called ranks. They are numbered 1 through 8 from White''s bottom edge upward. Watch the green row light up on rank 1.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","highlight":["a1"],"highlightRanks":[1]}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-board-setup','class-pre-board','Starting Position','White & Black armies','⚔️','preschool',15,0,'["pre-board-intro"]','[{"id":"armies","kind":"info","coach":"Each player starts with 16 pieces: 8 pawns on the second rank, rooks in the corners, knights next to them, bishops beside the knights, and the queen on her matching colour square (white queen on a light square). The king takes the remaining centre square.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","highlight":["d1","e1","d8","e8"],"highlightRanks":[1,2],"highlightFiles":["d","e"]},{"id":"watch-setup","kind":"observe","coach":"Watch a legal opening move — White pushes the e-pawn two squares forward along the e-file to e4.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4"],"highlight":["e2","e4"],"highlightFiles":["e"],"highlightRanks":[2,4]},{"id":"turns","kind":"info","coach":"White always moves first, then players alternate one move at a time. The pawn now sits on e4 — file e, rank 4.","fen":"rnbqkbnr/pppppppp/8/8/4P3/8/PPPP1PPP/RNBQKBNR b KQkq e3 0 1","highlight":["e4"],"highlightFiles":["e"],"highlightRanks":[4]}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-square-d5','class-pre-board','Find d5','Name a central square','📍','preschool',10,0,'["pre-board-setup"]','[{"id":"quiz-d5","kind":"quiz","coach":"","question":"Where is the square d5?","options":[{"label":"File d, rank 5 — a central square","emoji":"📍"},{"label":"File e, rank 4","emoji":"🎯"},{"label":"File d, rank 6","emoji":"⬆️"},{"label":"File c, rank 5","emoji":"⬅️"}],"correct":0,"explain":"d5 is file d (4th from the left) and rank 5 (5th row from White). Many battles happen in the centre!","failText":"Count files a→d, then ranks 1→5 from White''s bottom edge.","visual":"square","visualSquare":"d5"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-square-e4','class-pre-board','Reach e4','Name the square','♟️','preschool',10,0,'["pre-square-d5"]','[{"id":"quiz-e4","kind":"quiz","coach":"","question":"A pawn on e2 moves two squares forward. What square does it land on?","options":[{"label":"e4","emoji":"♟️"},{"label":"e3","emoji":"1️⃣"},{"label":"f4","emoji":"↗️"},{"label":"d4","emoji":"↖️"}],"correct":0,"explain":"e4 — file e, rank 4. Two squares straight ahead from e2.","failText":"From e2, count two ranks forward (not sideways).","visual":"square-path","visualSquares":["e2","e4"]}]',3);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-pieces-roster','class-pre-pieces','Meet the Army','Six piece types','♟️','preschool',15,0,'["pre-square-e4"]','[{"id":"roster","kind":"info","coach":"There are six kinds of pieces. Pawns (♟) are the foot soldiers — you have eight. Rooks (♜) look like castle towers. Knights (♞) look like horses and jump in an L. Bishops (♝) move diagonally. The Queen (♛) is the most powerful. The King (♚) is the most important — protect him at all costs!","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","highlight":["a1","b1","c1","d1","e1","f1","g1","h1","a2","b2","c2","d2","e2","f2","g2","h2"],"highlightRanks":[1,2]}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-pieces-queen','class-pre-pieces','Queen Power','Most valuable piece','♛','preschool',10,0,'["pre-pieces-roster"]','[{"id":"queen-value","kind":"quiz","coach":"","question":"Which piece is worth the most?","options":[{"label":"Queen ♛","emoji":"👑"},{"label":"King ♚","emoji":"🛡️"},{"label":"Pawn ♟","emoji":"♟️"},{"label":"Knight ♞","emoji":"🐴"}],"correct":0,"explain":"The queen combines rook and bishop powers — she is the strongest piece.","failText":"Think about which piece can move the farthest in one turn.","visual":"royalty"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-pieces-king','class-pre-pieces','Protect the King','Most important piece','♚','preschool',10,0,'["pre-pieces-queen"]','[{"id":"king-lost","kind":"quiz","coach":"","question":"Which piece must you never lose?","options":[{"label":"King ♚","emoji":"🛡️"},{"label":"Queen ♛","emoji":"👑"},{"label":"Rook ♜","emoji":"🏰"},{"label":"Bishop ♝","emoji":"⛪"}],"correct":0,"explain":"If your king cannot escape check, you lose (checkmate). Protect the king at all costs!","failText":"When the king is trapped with no escape, the game is over.","visual":"royalty"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-blocking','class-pre-rules','Blocked Paths','Pieces cannot jump','🚧','preschool',10,0,'["pre-pieces-king"]','[{"id":"blocking-quiz","kind":"quiz","coach":"","question":"Can a rook slide through a piece to reach a square beyond it?","options":[{"label":"No — pieces block the path","emoji":"🚧"},{"label":"Yes — rooks jump over pawns","emoji":"🦘"},{"label":"Only if the blocker is your own piece","emoji":"🤝"},{"label":"Only on the first move","emoji":"1️⃣"}],"correct":0,"explain":"Sliding pieces (rook, bishop, queen) must stop when they hit any piece. Knights are the exception — they jump.","failText":"Only knights can hop over blockers.","visual":"piece-roster"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-check-intro','class-pre-rules','What Is Check?','The king is attacked','⚠️','preschool',15,0,'["pre-rules-blocking"]','[{"id":"check-info","kind":"info","coach":"Check means your king is under attack. When you are in check, you must make a move that stops the attack — move the king, block the line, or capture the attacking piece. You may never ignore check.","fen":"k7/8/8/4q3/8/8/8/4K3 w - - 0 1","highlight":["e1","e5"],"highlightFiles":["e"],"arrows":[{"startSquare":"e5","endSquare":"e1","color":"#cf4324"}]}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-check-quiz','class-pre-rules','Check Quiz','King under attack','⚠️','preschool',10,0,'["pre-rules-check-intro"]','[{"id":"check-meaning","kind":"quiz","coach":"","question":"What does “check” mean?","options":[{"label":"Your king is being attacked","emoji":"⚠️"},{"label":"You won the game","emoji":"🏆"},{"label":"It is a draw","emoji":"🤝"},{"label":"You may skip your turn","emoji":"⏭️"}],"correct":0,"explain":"Check is a warning — your king is threatened and you must respond on your very next move.","failText":"When the king is attacked, that is check.","visual":"royalty"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-escape-intro','class-pre-rules','Escaping Check','Three ways out','🛡️','preschool',15,0,'["pre-rules-check-quiz"]','[{"id":"escape","kind":"info","coach":"Three ways to escape check: move the king to a safe square, block the attack with another piece, or capture the attacker. You will practice this in the Piece Moves class.","fen":"4k3/8/8/8/8/8/8/r3K3 w - - 0 1","highlight":["e1","a1"],"highlightFiles":["e"],"arrows":[{"startSquare":"a1","endSquare":"e1","color":"#cf4324"}]}]',3);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-checkmate-intro','class-pre-rules','Checkmate','No escape — game over','♚','preschool',15,0,'["pre-rules-escape-intro"]','[{"id":"mate-info","kind":"info","coach":"Checkmate is check with no legal escape. The king is attacked and cannot move to safety, the attack cannot be blocked, and the attacker cannot be captured. Checkmate ends the game — the player whose king is mated loses.","fen":"7k/6Q1/6K1/8/8/8/8/8 b - - 0 1","highlight":["h8","g7","g6"],"orientation":"white"}]',4);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-checkmate-quiz','class-pre-rules','Checkmate Quiz','Winning the game','🏆','preschool',10,0,'["pre-rules-checkmate-intro"]','[{"id":"mate-meaning","kind":"quiz","coach":"","question":"What happens when a player is checkmated?","options":[{"label":"They lose the game","emoji":"🏁"},{"label":"The game is a draw","emoji":"🤝"},{"label":"They get an extra turn","emoji":"⏭️"},{"label":"They swap colours","emoji":"🔄"}],"correct":0,"explain":"Checkmate = check with no escape. The game ends immediately and the mated player loses.","failText":"No legal move to escape check means checkmate — and a loss.","visual":"royalty"}]',5);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-stalemate','class-pre-rules','Stalemate','A surprising draw','🤝','preschool',10,0,'["pre-rules-checkmate-quiz"]','[{"id":"stalemate-quiz","kind":"quiz","coach":"","question":"What is stalemate?","options":[{"label":"No legal move, but the king is NOT in check — a draw","emoji":"🤝"},{"label":"The king is in check with no escape","emoji":"♚"},{"label":"Both players agree to stop","emoji":"✋"},{"label":"You lose a piece by accident","emoji":"😅"}],"correct":0,"explain":"Stalemate: it is your turn, you have no legal move, but your king is not in check. The game is a draw.","failText":"Stalemate is not checkmate — the king is safe but cannot move.","visual":"royalty"}]',6);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-promotion','class-pre-rules','Pawn Promotion','Reach the last rank','⬆️','preschool',15,0,'["pre-rules-stalemate"]','[{"id":"promotion-info","kind":"info","coach":"When a pawn reaches the far end of the board (the 8th rank for White, 1st for Black), it promotes — it becomes a queen, rook, bishop, or knight. Almost always you choose a queen!","fen":"8/4P3/8/8/8/8/8/4K2k w - - 0 1","highlight":["e7","e8"],"highlightFiles":["e"],"highlightRanks":[7,8],"arrows":[{"startSquare":"e7","endSquare":"e8","color":"#34d399"}]}]',7);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-promotion-quiz','class-pre-rules','Promotion Quiz','New piece choice','👑','preschool',10,0,'["pre-rules-promotion"]','[{"id":"promotion-choice","kind":"quiz","coach":"","question":"When a pawn promotes, what piece do players usually choose?","options":[{"label":"Queen","emoji":"👑"},{"label":"Another pawn","emoji":"♟️"},{"label":"King","emoji":"♚"},{"label":"You cannot choose — it stays a pawn","emoji":"🚫"}],"correct":0,"explain":"Queen is the default choice — she is the strongest piece. Sometimes under-promotion to a knight tricks your opponent!","failText":"Most promotions become queens for maximum power.","visual":"square-path","visualSquares":["e7","e8"]}]',8);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-castling','class-pre-rules','Castling','King safety special move','🏰','preschool',15,0,'["pre-rules-promotion-quiz"]','[{"id":"castle-info","kind":"info","coach":"Castling is a special one-time move: the king moves two squares toward a rook, and that rook jumps to the other side of the king. It tucks the king behind a wall of pawns — but only if neither piece has moved and no pieces block the way.","fen":"r3k2r/8/8/8/8/8/8/R3K2R w KQkq - 0 1","highlight":["e1","g1","h1"],"highlightFiles":["e","f","g","h"],"highlightRanks":[1],"arrows":[{"startSquare":"e1","endSquare":"g1","color":"#5b5bd6"},{"startSquare":"h1","endSquare":"f1","color":"#34d399"}]}]',9);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rules-castling-quiz','class-pre-rules','Castling Quiz','King + rook team up','🏰','preschool',10,0,'["pre-rules-castling"]','[{"id":"castle-purpose","kind":"quiz","coach":"","question":"Why do players castle?","options":[{"label":"To tuck the king safely behind pawns","emoji":"🛡️"},{"label":"To capture the enemy queen","emoji":"👑"},{"label":"To promote a pawn","emoji":"⬆️"},{"label":"To skip a turn","emoji":"⏭️"}],"correct":0,"explain":"Castling gets the king off the centre and connects the rooks — a key opening goal.","failText":"Castling is about king safety, not capturing.","visual":"piece-roster"}]',10);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-moves-e4','class-pre-moves','Play e4','Your first pawn move','♟️','preschool',15,0,'["pre-rules-castling-quiz"]','[{"id":"play-e4","kind":"move","coach":"Your turn: push the pawn from e2 to the square e4 on the e-file.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","solution":["e2:e4"],"highlight":["e2"],"highlightFiles":["e"],"highlightRanks":[2,4],"successText":"That''s e4! File e, rank 4.","failText":"Move the pawn on e2 forward two squares to e4.","tag":"preschool"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-pawn-basics','class-pre-moves','Pawn Rules','Forward & diagonal','♟️','preschool',20,0,'["pre-moves-e4"]','[{"id":"forward","kind":"info","coach":"Pawns move straight forward one square. From their starting row they may optionally move two squares. Pawns never move backward or sideways.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","highlight":["e2"],"highlightFiles":["e"],"highlightRanks":[2],"arrows":[{"startSquare":"e2","endSquare":"e3","color":"#5b5bd6"},{"startSquare":"e2","endSquare":"e4","color":"#34d399"}]},{"id":"capture-rule","kind":"info","coach":"Pawns capture differently from how they move — they capture one square diagonally forward onto an adjacent file. Here the e-pawn captures on d5.","fen":"k7/8/8/3p4/4P3/8/8/7K w - - 0 1","highlight":["e4","d5"],"highlightFiles":["e","d"],"highlightRanks":[4,5],"arrows":[{"startSquare":"e4","endSquare":"d5","color":"#cf4324"}]},{"id":"capture-try","kind":"move","coach":"Capture the black pawn on d5 with your pawn on e4.","fen":"k7/8/8/3p4/4P3/8/8/7K w - - 0 1","solution":["e4:d5"],"highlight":["e4","d5"],"successText":"Correct — pawns capture on the diagonal!","failText":"Move your e4 pawn diagonally onto d5.","tag":"preschool"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-pawn-quiz','class-pre-moves','Pawn Quiz','Forward only','♟️','preschool',10,0,'["pre-pawn-basics"]','[{"id":"pawn-direction","kind":"quiz","coach":"","question":"Which way can a pawn move?","options":[{"label":"Straight forward only","emoji":"⬆️"},{"label":"Backward or sideways","emoji":"↔️"},{"label":"Diagonally like a bishop","emoji":"↗️"},{"label":"Any direction one square","emoji":"🎯"}],"correct":0,"explain":"Pawns march straight forward. They capture one square diagonally forward — never backward.","failText":"Pawns are foot soldiers — they only advance toward the enemy.","visual":"square-path","visualSquares":["e2","e4"]}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-knight-basics','class-pre-moves','Knight Rules','The L-shaped jumper','🐴','preschool',20,0,'["pre-pawn-quiz"]','[{"id":"l-shape","kind":"info","coach":"Knights move in an L-shape: two squares in one direction, then one square sideways. They are the only pieces that can jump over other pieces.","fen":"k7/8/4p3/8/3N4/8/8/7K w - - 0 1","highlight":["d4","e6"],"highlightFiles":["d","e"],"highlightRanks":[4,6],"arrows":[{"startSquare":"d4","endSquare":"e6","color":"#5b5bd6"},{"startSquare":"d4","endSquare":"f5","color":"#5b5bd6"},{"startSquare":"d4","endSquare":"f3","color":"#5b5bd6"}]},{"id":"capture","kind":"move","coach":"Your knight on d4 can capture the pawn on e6. Play the move!","fen":"k7/8/4p3/8/3N4/8/8/7K w - - 0 1","solution":["d4:e6"],"highlight":["d4","e6"],"successText":"Hop! Knights jump in an L.","failText":"Jump the knight from d4 to e6 (two up, one right).","tag":"preschool"}]',3);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-knight-quiz','class-pre-moves','Knight Quiz','Jump over pieces','🐴','preschool',10,0,'["pre-knight-basics"]','[{"id":"knight-jump","kind":"quiz","coach":"","question":"What makes the knight special?","options":[{"label":"It can jump over other pieces","emoji":"🦘"},{"label":"It slides any distance","emoji":"➡️"},{"label":"It only moves diagonally","emoji":"↗️"},{"label":"It captures like a pawn","emoji":"♟️"}],"correct":0,"explain":"Knights are the only pieces that leap over blockers — two squares one way, one square sideways.","failText":"Remember the L-shape jump — nothing can block a knight''s path.","visual":"piece-roster"}]',4);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rook-basics','class-pre-moves','Rook Rules','Straight-line slides','♜','preschool',20,0,'["pre-knight-quiz"]','[{"id":"rook-slide","kind":"info","coach":"Rooks move any number of squares along a rank or file — straight up, down, left, or right. They cannot turn corners or jump over pieces.","fen":"k7/8/8/8/3p4/8/8/3R3K w - - 0 1","highlight":["d1","d4"],"highlightFiles":["d"],"arrows":[{"startSquare":"d1","endSquare":"d8","color":"#5b5bd6"}]},{"id":"rook-observe","kind":"observe","coach":"Watch the rook slide up the d-file and capture the pawn on d4.","fen":"k7/8/8/8/3p4/8/8/3R3K w - - 0 1","moves":["d1:d4"],"highlight":["d1","d4"],"highlightFiles":["d"]},{"id":"rook-capture","kind":"move","coach":"Your turn: slide the rook from d1 to d4 and capture the pawn.","fen":"k7/8/8/8/3p4/8/8/3R3K w - - 0 1","solution":["d1:d4"],"highlight":["d1","d4"],"highlightFiles":["d"],"successText":"Straight up the file — classic rook power!","failText":"Slide the rook from d1 to d4 along the d-file.","tag":"preschool"}]',5);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-rook-quiz','class-pre-moves','Rook Quiz','Ranks & files','♜','preschool',10,0,'["pre-rook-basics"]','[{"id":"rook-direction","kind":"quiz","coach":"","question":"How does a rook move?","options":[{"label":"Straight along ranks and files","emoji":"➕"},{"label":"Diagonally only","emoji":"↗️"},{"label":"In an L-shape","emoji":"🐴"},{"label":"One square in any direction","emoji":"🎯"}],"correct":0,"explain":"Rooks ride straight lines — like a castle tower sliding along rows and columns.","failText":"Rooks go straight, not diagonally.","visual":"piece-roster"}]',6);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-bishop-basics','class-pre-moves','Bishop Rules','Diagonal slides','♝','preschool',20,0,'["pre-rook-quiz"]','[{"id":"bishop-slide","kind":"info","coach":"Bishops move any number of squares diagonally. Each bishop stays on one colour for the entire game — a light-squared bishop never visits a dark square.","fen":"k7/8/8/8/2p5/5B2/8/7K w - - 0 1","highlight":["f3","c6"],"highlightFiles":["f","c"],"highlightRanks":[3,6],"arrows":[{"startSquare":"f3","endSquare":"c6","color":"#7c5cd6"}]},{"id":"bishop-capture","kind":"move","coach":"Capture the pawn on c6 with your bishop on f3.","fen":"k7/8/8/8/2p5/5B2/8/7K w - - 0 1","solution":["f3:c6"],"highlight":["f3","c6"],"successText":"Diagonal capture — bishops cut across the board!","failText":"Slide the bishop from f3 to c6 along the diagonal.","tag":"preschool"}]',7);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-bishop-quiz','class-pre-moves','Bishop Quiz','One colour forever','♝','preschool',10,0,'["pre-bishop-basics"]','[{"id":"bishop-colour","kind":"quiz","coach":"","question":"Which squares can a bishop reach?","options":[{"label":"Only squares of one colour","emoji":"🟫"},{"label":"Every square on the board","emoji":"🌈"},{"label":"Only the four centre squares","emoji":"🎯"},{"label":"Only ranks, never files","emoji":"➡️"}],"correct":0,"explain":"A bishop on a light square always stays on light squares — same for dark bishops.","failText":"Bishops slide diagonally, so they never change square colour.","visual":"piece-roster"}]',8);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-queen-moves','class-pre-moves','Queen Movement','Rook + bishop combined','♛','preschool',20,0,'["pre-bishop-quiz"]','[{"id":"queen-slide","kind":"info","coach":"The queen combines rook and bishop powers — she slides straight or diagonally any distance. That makes her the strongest piece, but she still cannot jump over blockers.","fen":"k7/8/8/8/3Q4/8/8/7K w - - 0 1","highlight":["d4"],"highlightFiles":["d"],"highlightRanks":[4],"arrows":[{"startSquare":"d4","endSquare":"d8","color":"#5b5bd6"},{"startSquare":"d4","endSquare":"h4","color":"#7c5cd6"},{"startSquare":"d4","endSquare":"h8","color":"#34d399"}]},{"id":"queen-observe","kind":"observe","coach":"Watch the queen sweep along the fourth rank from d4 to h4.","fen":"k7/8/8/8/3Q4/8/8/7K w - - 0 1","moves":["d4:h4"],"highlight":["d4","h4"],"highlightRanks":[4]},{"id":"queen-move","kind":"move","coach":"Slide your queen from d4 to h4 along the rank.","fen":"k7/8/8/8/3Q4/8/8/7K w - - 0 1","solution":["d4:h4"],"highlight":["d4","h4"],"highlightRanks":[4],"successText":"The queen owns straight lines and diagonals!","failText":"Move the queen from d4 to h4 along rank 4.","tag":"preschool"}]',9);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-queen-slide-quiz','class-pre-moves','Queen Quiz','How she moves','♛','preschool',10,0,'["pre-queen-moves"]','[{"id":"queen-movement","kind":"quiz","coach":"","question":"How can the queen move?","options":[{"label":"Straight or diagonally, any distance","emoji":"👑"},{"label":"Only diagonally","emoji":"↗️"},{"label":"Only one square at a time","emoji":"1️⃣"},{"label":"In an L-shape like a knight","emoji":"🐴"}],"correct":0,"explain":"The queen = rook + bishop. She slides in eight directions but cannot jump over pieces.","failText":"Think rook lines plus bishop diagonals.","visual":"royalty"}]',10);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-king-moves','class-pre-moves','King Movement','One careful step','♚','preschool',20,0,'["pre-queen-slide-quiz"]','[{"id":"king-step","kind":"info","coach":"The king moves one square in any direction — straight, diagonal, or sideways. He is slow but must stay safe: if he is attacked and cannot escape, the game is over.","fen":"k7/8/8/8/3K4/8/8/7R w - - 0 1","highlight":["d4"],"arrows":[{"startSquare":"d4","endSquare":"e5","color":"#5b5bd6"},{"startSquare":"d4","endSquare":"c5","color":"#5b5bd6"},{"startSquare":"d4","endSquare":"e4","color":"#34d399"},{"startSquare":"d4","endSquare":"c4","color":"#34d399"}]},{"id":"king-move","kind":"move","coach":"Move your king from d4 to e5 — one square diagonally forward.","fen":"k7/8/8/8/3K4/8/8/7R w - - 0 1","solution":["d4:e5"],"highlight":["d4","e5"],"successText":"One square at a time — the king stays cautious.","failText":"Slide the king one square from d4 to e5.","tag":"preschool"}]',11);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-king-quiz','class-pre-moves','King Quiz','One square only','♚','preschool',10,0,'["pre-king-moves"]','[{"id":"king-range","kind":"quiz","coach":"","question":"How far can the king move on one turn?","options":[{"label":"One square in any direction","emoji":"1️⃣"},{"label":"Any distance like a queen","emoji":"👑"},{"label":"Two squares like a pawn''s first move","emoji":"♟️"},{"label":"Only along the back rank","emoji":"➡️"}],"correct":0,"explain":"The king is the slowest piece — one square per move — but losing him means losing the game.","failText":"The king never slides across the whole board.","visual":"royalty"}]',12);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-moves-escape-check','class-pre-moves','Escape Check','Move the king safe','🛡️','preschool',15,0,'["pre-king-quiz"]','[{"id":"escape-move","kind":"move","coach":"You are in check! Move your king from e1 to a safe square.","fen":"4k3/8/8/8/8/8/8/r3K3 w - - 0 1","solution":["e1:e2"],"highlight":["e1"],"successText":"King safe — check escaped!","failText":"Move the king from e1 to e2 (or another safe square).","tag":"preschool"}]',13);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-moves-promotion','class-pre-moves','Promote a Pawn','Pawn becomes a queen','👑','preschool',15,0,'["pre-moves-escape-check"]','[{"id":"promotion-move","kind":"move","coach":"Push the pawn from e7 to e8 and promote it to a queen!","fen":"8/4P3/8/8/8/8/8/4K2k w - - 0 1","solution":["e7:e8"],"highlight":["e7","e8"],"highlightFiles":["e"],"successText":"Promotion! Your pawn becomes a queen.","failText":"Move the pawn from e7 to e8.","tag":"preschool"}]',14);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-moves-castling','class-pre-moves','Castle Kingside','Watch the special move','🏰','preschool',15,0,'["pre-moves-promotion"]','[{"id":"castle-watch","kind":"observe","coach":"Watch kingside castling: the king slides to g1 and the h1-rook hops to f1.","fen":"r3k2r/8/8/8/8/8/8/R3K2R w KQkq - 0 1","moves":["e1:g1"],"highlight":["e1","g1","f1","h1"],"highlightRanks":[1]}]',15);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-files','class-pre-language','What Are Files?','Vertical columns a–h','📊','preschool',10,0,'["pre-moves-castling"]','[{"id":"files","kind":"quiz","coach":"","question":"What are the files?","options":[{"label":"Vertical columns named a–h","emoji":"📊"},{"label":"Horizontal rows numbered 1–8","emoji":"📏"},{"label":"Diagonal lines across the board","emoji":"↗️"},{"label":"The four corners only","emoji":"🔲"}],"correct":0,"explain":"Files are the eight vertical columns, labelled a through h from left to right (White''s view).","failText":"Files go up and down — like columns in a spreadsheet.","visual":"files"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-e-file','class-pre-language','The e-file','Where kings start','♚','preschool',10,0,'["pre-notation-files"]','[{"id":"e-file","kind":"quiz","coach":"","question":"What is the e-file?","options":[{"label":"The middle file — both kings start here","emoji":"♚"},{"label":"The leftmost file (a-file)","emoji":"⬅️"},{"label":"The back rank for White","emoji":"1️⃣"},{"label":"A diagonal from a1 to h8","emoji":"↗️"}],"correct":0,"explain":"The e-file is the 5th column from the left — White''s king starts on e1, Black''s on e8.","failText":"Count files from the left: a, b, c, d, e…","visual":"e-file"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-ranks','class-pre-language','What Are Ranks?','Horizontal rows 1–8','📏','preschool',10,0,'["pre-notation-e-file"]','[{"id":"ranks","kind":"quiz","coach":"","question":"What are the ranks?","options":[{"label":"Horizontal rows numbered 1–8","emoji":"📏"},{"label":"Vertical columns a–h","emoji":"📊"},{"label":"Only the pawn rows","emoji":"♟️"},{"label":"Square colours (light/dark)","emoji":"🎨"}],"correct":0,"explain":"Ranks are numbered 1–8 from White''s side upward. Back-row pieces sit on rank 1; pawns on rank 2.","failText":"Ranks run left-to-right — like floors in a building.","visual":"ranks"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-d6','class-pre-language','Reading d6','File + rank = square','📍','preschool',10,0,'["pre-notation-ranks"]','[{"id":"d6","kind":"quiz","coach":"","question":"How do you read the square d6?","options":[{"label":"File d + rank 6","emoji":"📍"},{"label":"File 6 + rank d","emoji":"🔢"},{"label":"The 6th file, 4th rank","emoji":"❌"},{"label":"Diagonal square near the edge","emoji":"↗️"}],"correct":0,"explain":"d6 = file d (4th from the left) + rank 6 (6 rows up from White). A central square.","failText":"Letter first (file), number second (rank).","visual":"square","visualSquare":"d6"}]',3);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-piece-letters','class-pre-language','Piece Letters','K, Q, R, B, N','🔤','preschool',10,0,'["pre-notation-d6"]','[{"id":"knight-letter","kind":"quiz","coach":"","question":"What letter do we use for a Knight in chess notation?","options":[{"label":"N","emoji":"🐴"},{"label":"K","emoji":"♚"},{"label":"R","emoji":"♜"},{"label":"B","emoji":"♝"}],"correct":0,"explain":"N = Knight (K is reserved for the King). So Nf3 means the knight moves to f3.","failText":"K is the King — knights use N because K was taken.","visual":"notation-letters"}]',4);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-pawn-e4','class-pre-language','Writing e4','Pawn moves in notation','♟️','preschool',10,0,'["pre-notation-piece-letters"]','[{"id":"pawn-notation-e4","kind":"quiz","coach":"","question":"How do we write the pawn move to e4?","options":[{"label":"e4","emoji":"♟️"},{"label":"Pe4","emoji":"🅿️"},{"label":"e2-e4","emoji":"↔️"},{"label":"E4","emoji":"🔤"}],"correct":0,"explain":"Pawn moves are just the destination square — e4 means a pawn lands on e4.","failText":"No piece letter for pawns — only the square name.","visual":"square-path","visualSquares":["e2","e4"]}]',5);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-pawn-capture','class-pre-language','Writing exd5','Pawn captures in notation','⚔️','preschool',10,0,'["pre-notation-pawn-e4"]','[{"id":"pawn-notation-capture","kind":"quiz","coach":"","question":"What does exd5 mean?","options":[{"label":"Pawn on the e-file captures on d5","emoji":"⚔️"},{"label":"Knight jumps to d5","emoji":"🐴"},{"label":"King moves to d5","emoji":"♚"},{"label":"Bishop slides to d5","emoji":"♝"}],"correct":0,"explain":"exd5 = a pawn on the e-file captures on d5. The x marks a capture; the file letter shows which pawn.","failText":"Look for the file letter before the x — that''s the pawn that moved.","visual":"notation-capture"}]',6);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-watch','class-pre-language','Watch Nf3 & Qd5','See notation in action','▶️','preschool',15,0,'["pre-notation-pawn-capture"]','[{"id":"watch-nf3","kind":"observe","coach":"Watch Nf3 — the knight from g1 hops to f3.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["g1:f3"],"highlight":["g1","f3"],"highlightFiles":["g","f"],"highlightRanks":[1,3]},{"id":"watch-qd5","kind":"observe","coach":"Watch Qd5 — the queen slides from d4 to d5 along the d-file.","fen":"rnbqkbnr/pppp1ppp/8/8/3Q4/8/PPPPPPPP/RNB1KBNR w KQkq - 0 1","moves":["d4:d5"],"highlight":["d4","d5"],"highlightFiles":["d"],"highlightRanks":[4,5]}]',7);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-read-d6','class-pre-language','Read ''pawn to d6''','Decode a written move','📖','preschool',10,0,'["pre-notation-watch"]','[{"id":"to-d6","kind":"quiz","coach":"","question":"What does ''pawn to d6'' mean?","options":[{"label":"Move a pawn so it lands on d6","emoji":"♟️"},{"label":"Capture everything on the d-file","emoji":"⚔️"},{"label":"Move the king to d6","emoji":"♚"},{"label":"Promote a pawn on d6","emoji":"👑"}],"correct":0,"explain":"Find file d, rank 6 — push the pawn on d5 one square forward to d6.","failText":"It''s a pawn move to the square d6 (file d, rank 6).","visual":"square-path","visualSquares":["d5","d6"]}]',8);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pre-notation-practice','class-pre-language','Play the Move','d6 & Nf3 on the board','🎯','preschool',20,0,'["pre-notation-read-d6"]','[{"id":"play-d6","kind":"move","coach":"Play pawn to d6 — push the pawn from d5 forward to d6.","fen":"k7/8/8/3P4/8/8/8/7K w - - 0 1","solution":["d5:d6"],"highlight":["d5"],"highlightFiles":["d"],"highlightRanks":[5,6],"successText":"d6! You read the square and played the right move.","failText":"Move the pawn on d5 one square forward to d6.","tag":"preschool"},{"id":"play-nf3","kind":"move","coach":"Play Nf3 — develop the knight from g1 to f3.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","solution":["g1:f3"],"highlight":["g1"],"highlightFiles":["g","f"],"highlightRanks":[1,3],"successText":"Nf3 — well done! You are reading chess notation.","failText":"Hop the knight from g1 to f3.","tag":"preschool"},{"id":"finish","kind":"info","coach":"You now know the board, the pieces, and how to read moves like d6, e4, Nf3, and Qd5. Pre-School complete — head to Elementary when you are ready, or replay any lesson for practice!","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","highlight":["e4","d5"]}]',9);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('board-basics','class-pieces','The Battlefield','Meet the board','🪵','basics',20,0,'[]','[{"id":"intro","kind":"info","coach":"Welcome to the academy! Chess is played on 64 squares. White always moves first.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"},{"id":"watch-open","kind":"observe","coach":"Watch a calm opening: both sides claim the centre with their e-pawns.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4","e7:e5"]}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pawn-power','class-pieces','Pawn Power','Move & capture','♟️','pawns',30,0,'["board-basics"]','[{"id":"center","kind":"move","coach":"Pawns move forward. Push your e-pawn two squares to grab the centre!","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","solution":["e2:e4"],"highlight":["e2"],"arrows":[{"startSquare":"e2","endSquare":"e4","color":"#34d399"}],"successText":"Beautiful — the centre is yours!","failText":"Try pushing the e-pawn (e2) up two squares to e4.","tag":"pawns"},{"id":"capture","kind":"move","coach":"Pawns capture diagonally. Take the enemy pawn!","fen":"k7/8/8/3p4/4P3/8/8/7K w - - 0 1","solution":["e4:d5"],"highlight":["e4","d5"],"successText":"Snap! That''s how pawns capture.","failText":"Capture diagonally: move your e4 pawn onto d5.","tag":"pawns"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('rook-roads','class-pieces','Rook Roads','Straight lines','🏰','rooks',30,0,'["pawn-power"]','[{"id":"info","kind":"info","coach":"Rooks slide any distance in straight lines — along ranks and files.","fen":"k7/8/8/8/3p4/8/8/3R3K w - - 0 1","arrows":[{"startSquare":"d1","endSquare":"d4","color":"#5b5bd6"}]},{"id":"capture","kind":"move","coach":"Use your rook''s straight-line power to capture the pawn.","fen":"k7/8/8/8/3p4/8/8/3R3K w - - 0 1","solution":["d1:d4"],"highlight":["d1","d4"],"successText":"Direct hit! Rooks love open files.","failText":"Slide the rook straight up the d-file onto d4.","tag":"rooks"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('knight-hops','class-pieces','Knight Hops','The L-shape','🐴','knights',35,0,'["rook-roads"]','[{"id":"info","kind":"info","coach":"Knights move in an L: two squares one way, then one across. They leap over pieces!","fen":"k7/8/4p3/8/3N4/8/8/7K w - - 0 1","arrows":[{"startSquare":"d4","endSquare":"e6","color":"#5b5bd6"}]},{"id":"capture","kind":"move","coach":"Hop your knight in an L to capture the pawn on e6.","fen":"k7/8/4p3/8/3N4/8/8/7K w - - 0 1","solution":["d4:e6"],"highlight":["d4","e6"],"successText":"Nice leap! That''s the knight''s superpower.","failText":"From d4, the L-shaped hop to e6 captures the pawn.","tag":"knights"}]',3);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('exam-pieces','class-pieces','Piece Movement Exam','Pass to graduate','📝','exam',60,1,'[]','[{"id":"q1","kind":"move","coach":"Exam Q1 — capture the pawn with your pawn.","fen":"k7/8/8/3p4/4P3/8/8/7K w - - 0 1","solution":["e4:d5"],"successText":"Correct.","failText":"Pawns capture diagonally.","tag":"exam"},{"id":"q2","kind":"move","coach":"Exam Q2 — capture the pawn with your rook.","fen":"k7/8/8/8/3p4/8/8/3R3K w - - 0 1","solution":["d1:d4"],"successText":"Correct.","failText":"Rooks move in straight lines.","tag":"exam"},{"id":"q3","kind":"move","coach":"Exam Q3 — capture the pawn with your knight.","fen":"k7/8/4p3/8/3N4/8/8/7K w - - 0 1","solution":["d4:e6"],"successText":"Correct.","failText":"Knights move in an L.","tag":"exam"}]',99);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('deliver-check','class-checkmate','Say Check!','Attack the king','⚡','checks',35,0,'["knight-hops"]','[{"id":"info","kind":"info","coach":"When you attack the enemy king, that''s CHECK. The opponent must respond at once.","fen":"k7/8/8/8/8/8/8/3RK3 w - - 0 1"},{"id":"give","kind":"move","coach":"Slide your rook to the 8th rank to put the black king in check!","fen":"k7/8/8/8/8/8/8/3RK3 w - - 0 1","solution":["d1:d8"],"highlight":["a8"],"successText":"Check! The king has to react.","failText":"Bring the rook to d8 — it attacks along the 8th rank to the king.","tag":"checks"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('mate-in-one','class-checkmate','Checkmate!','End the game','👑','checkmate',45,0,'["deliver-check"]','[{"id":"info","kind":"info","coach":"Checkmate is a check the king cannot escape. It wins the game instantly.","fen":"6k1/5ppp/8/8/8/8/5PPP/R5K1 w - - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the rook swing to the back rank — the king is fenced in by its own pawns.","fen":"6k1/5ppp/8/8/8/8/5PPP/R5K1 w - - 0 1","moves":["a1:a8"]},{"id":"mate","kind":"move","coach":"Now you do it — find the back-rank mate!","fen":"6k1/5ppp/8/8/8/8/5PPP/R5K1 w - - 0 1","solution":["a1:a8"],"highlight":["g8"],"successText":"Checkmate! The king can''t escape its own wall of pawns.","failText":"Send the rook all the way to a8 — the king is boxed in.","tag":"checkmate"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('opening-principles','class-principles','Opening Rules','Centre, develop, castle','🚀','openings',40,0,'["pawn-power"]','[{"id":"info","kind":"info","coach":"Three golden rules: control the centre, develop your knights and bishops, and castle your king to safety.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"},{"id":"watch","kind":"observe","coach":"Watch ideal development: centre pawn, both knights, a bishop, then castling.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4","e7:e5","g1:f3","b8:c6","f1:c4","g8:f6","e1:g1"]},{"id":"develop","kind":"move","coach":"Your turn: develop a knight toward the centre.","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/8/PPPP1PPP/RNBQKBNR w KQkq - 0 2","solution":["g1:f3"],"highlight":["g1"],"successText":"Great — knights before bishops, toward the centre.","failText":"Develop the kingside knight from g1 to f3.","tag":"openings"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('italian-game','class-openings','Italian Game','1.e4 e5 2.Nf3 Nc6 3.Bc4','🇮🇹','openings',50,0,'["opening-principles"]','[{"id":"info","kind":"info","coach":"The Italian Game is a classical opening: quick development and a bishop aimed at f7, Black''s weakest point.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the main line of the Italian Game unfold.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4","e7:e5","g1:f3","b8:c6","f1:c4"]},{"id":"try","kind":"move","coach":"Play the move that defines the Italian — develop the bishop to eye f7.","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 4 3","solution":["f1:c4"],"highlight":["f1","f7"],"successText":"That''s the Italian Bishop — pointing straight at f7!","failText":"Develop the light-squared bishop from f1 to c4.","tag":"openings"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('ruy-lopez','class-openings','Ruy Lopez','1.e4 e5 2.Nf3 Nc6 3.Bb5','🇪🇸','openings',50,0,'["italian-game"]','[{"id":"info","kind":"info","coach":"The Ruy Lopez pressures the c6 knight that defends e5 — one of the most respected openings in chess.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the Spanish bishop pin the defender of e5.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4","e7:e5","g1:f3","b8:c6","f1:b5"]},{"id":"try","kind":"move","coach":"Play the Ruy Lopez move — attack the knight on c6.","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 4 3","solution":["f1:b5"],"highlight":["f1","c6"],"successText":"The Spanish bishop — pressure on c6!","failText":"Develop the bishop from f1 to b5, attacking the knight.","tag":"openings"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sicilian-defense','class-openings','Sicilian Defense','Black fights for the centre','⚔️','openings',50,0,'["italian-game"]','[{"id":"info","kind":"info","coach":"Against 1.e4, the Sicilian (1...c5) fights for the centre asymmetrically — the most popular reply at every level.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the Open Sicilian: White trades the d-pawn for active piece play.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4","c7:c5","g1:f3","d7:d6","d2:d4","c5:d4","f3:d4","g8:f6","b1:c3"]},{"id":"try","kind":"move","coach":"Facing the Sicilian, develop your knight and prepare d4.","fen":"rnbqkbnr/pp1ppppp/8/2p5/4P3/8/PPPP1PPP/RNBQKBNR w KQkq c6 0 2","solution":["g1:f3"],"highlight":["g1"],"successText":"Develop and prepare to strike with d4.","failText":"Develop the knight from g1 to f3.","tag":"openings"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('fork-master','class-tactics','The Fork','Two targets, one move','🍴','fork',50,0,'["knight-hops"]','[{"id":"info","kind":"info","coach":"A FORK attacks two pieces at once. Knights are the deadliest forkers.","fen":"r3k3/8/8/3N4/8/8/8/4K3 w - - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the knight leap to c7 — checking the king and hitting the rook.","fen":"r3k3/8/8/3N4/8/8/8/4K3 w - - 0 1","moves":["d5:c7"]},{"id":"fork","kind":"move","coach":"Your turn — find the royal fork!","fen":"r3k3/8/8/3N4/8/8/8/4K3 w - - 0 1","solution":["d5:c7"],"successText":"Royal fork! You check the king and win the rook next move.","failText":"Look for Nc7 — it checks the king on e8 and hits the rook on a8.","tag":"fork"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('pin-it','class-advtactics','The Pin','Freeze a defender','📌','pin',50,0,'["fork-master"]','[{"id":"info","kind":"info","coach":"A PIN freezes a piece: it can''t move because a more valuable piece sits behind it. Pin the knight that guards e5.","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 4 3"},{"id":"pin","kind":"move","coach":"Play the bishop move that pins the c6 knight to the king.","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 4 3","solution":["f1:b5"],"highlight":["c6"],"successText":"Pinned! The knight can''t move — it shields its king.","failText":"Bishop to b5 pins the knight on c6 to the king on e8.","tag":"pin"}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('skewer-it','class-advtactics','The Skewer','Attack through a king','🍢','skewer',50,0,'["pin-it"]','[{"id":"info","kind":"info","coach":"A SKEWER is a pin in reverse: check the king so it must step aside, then capture the piece behind it.","fen":"q7/8/8/k7/8/8/8/1R4K1 w - - 0 1"},{"id":"skewer","kind":"move","coach":"Check the king along the a-file — next move you''ll win the queen!","fen":"q7/8/8/k7/8/8/8/1R4K1 w - - 0 1","solution":["b1:a1"],"highlight":["a8"],"successText":"Skewer! The king must move and the queen falls.","failText":"Rook to a1 checks the king; the queen on a8 is then exposed.","tag":"skewer"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('discovered-attack','class-advtactics','Discovered Attack','Unmask a hidden threat','🎭','discovery',55,0,'["skewer-it"]','[{"id":"info","kind":"info","coach":"A DISCOVERED ATTACK: move one piece to unveil an attack from the piece behind it. Your knight hides the rook''s aim at the queen.","fen":"q5k1/8/8/8/8/N7/8/R5K1 w - - 0 1"},{"id":"discover","kind":"move","coach":"Move the knight off the a-file to discover your rook''s attack on the queen.","fen":"q5k1/8/8/8/8/N7/8/R5K1 w - - 0 1","solution":["a3:c4","a3:b5","a3:c2"],"highlight":["a8"],"successText":"Discovered! The rook now attacks the queen on a8.","failText":"Move the knight away from the a-file (e.g. to c4) to unveil the rook.","tag":"discovery"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('endgame-opposition','class-endgame','The Opposition','King vs king','🤴','opposition',45,0,'["mate-in-one"]','[{"id":"info","kind":"info","coach":"In king endgames, the OPPOSITION wins ground: stand your king directly facing the enemy with one square between — the side NOT to move must give way.","fen":"4k3/8/8/8/8/8/8/4K3 w - - 0 1"},{"id":"watch","kind":"observe","coach":"Watch White march up and seize the opposition on e4 vs e6.","fen":"4k3/8/8/8/8/8/8/4K3 w - - 0 1","moves":["e1:e2","e8:e7","e2:e3","e7:e6","e3:e4"]}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('endgame-promotion','class-endgame','Queening a Pawn','Promotion','👑','endgame',45,0,'["endgame-opposition"]','[{"id":"info","kind":"info","coach":"A pawn that reaches the last rank becomes a queen. Converting an extra pawn is how most endgames are won.","fen":"8/4P3/8/8/8/8/8/4K1k1 w - - 0 1"},{"id":"promote","kind":"move","coach":"Push the pawn home — promote to a queen!","fen":"8/4P3/8/8/8/8/8/4K1k1 w - - 0 1","solution":["e7:e8"],"highlight":["e7","e8"],"successText":"A brand-new queen! That''s a winning advantage.","failText":"Advance the e7 pawn to e8 to promote.","tag":"endgame"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('endgame-qmate','class-endgame','King & Queen Mate','Finish the game','♛','checkmate',55,0,'["endgame-promotion"]','[{"id":"info","kind":"info","coach":"With a queen and king you can force mate against a lone king. The king does the cornering, the queen delivers.","fen":"k7/4Q3/1K6/8/8/8/8/8 w - - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the queen step in, protected by the king — checkmate.","fen":"k7/4Q3/1K6/8/8/8/8/8 w - - 0 1","moves":["e7:a7"]},{"id":"mate","kind":"move","coach":"Now you deliver it — the king on b6 guards the queen.","fen":"k7/4Q3/1K6/8/8/8/8/8 w - - 0 1","solution":["e7:a7"],"highlight":["a8"],"successText":"Checkmate! King and queen working as a team.","failText":"Bring the queen to a7 — your king on b6 protects her.","tag":"checkmate"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-gen-openings-c1-l1','sem-gen-openings-c1','Italian Game: Main Line','1.e4 e5 2.Nf3 Nc6 3.Bc4','🇮🇹','opening',20,0,'[]','[{"id":"intro","kind":"info","coach":"The Italian Game — one of chess''s great openings. Watch the main line, then play it yourself.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the Italian Game unfold move by move.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4","e7:e5","g1:f3","b8:c6","f1:c4"]}]',0);
