INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-gen-openings-c1-l3','sem-gen-openings-c1','Italian Game: Key Moves 2','1 moves','🇮🇹','opening',15,0,'[]','[{"id":"s0","kind":"move","coach":"Play the Italian Game''s next book move.","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 2 3","solution":["f1:c4"],"highlight":["c4"],"successText":"Right move!","failText":"That''s not the main line — try again.","tag":"opening"}]',2);
