INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-gen-openings-c2-l2','sem-gen-openings-c2','Ruy Lopez: Key Moves 1','2 moves','🇪🇸','opening',15,0,'[]','[{"id":"s0","kind":"move","coach":"Play the Ruy Lopez''s next book move.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","solution":["e2:e4"],"highlight":["e4"],"successText":"Right move!","failText":"That''s not the main line — try again.","tag":"opening"},{"id":"s1","kind":"move","coach":"Play the Ruy Lopez''s next book move.","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/8/PPPP1PPP/RNBQKBNR w KQkq - 0 2","solution":["g1:f3"],"highlight":["f3"],"successText":"Right move!","failText":"That''s not the main line — try again.","tag":"opening"}]',1);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-gen-openings-c2-l3','sem-gen-openings-c2','Ruy Lopez: Key Moves 2','1 moves','🇪🇸','opening',15,0,'[]','[{"id":"s0","kind":"move","coach":"Play the Ruy Lopez''s next book move.","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 2 3","solution":["f1:b5"],"highlight":["b5"],"successText":"Right move!","failText":"That''s not the main line — try again.","tag":"opening"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-gen-openings-c3-l1','sem-gen-openings-c3','Sicilian Defense: Main Line','The Open Sicilian','⚔️','opening',20,0,'[]','[{"id":"intro","kind":"info","coach":"The Sicilian Defense — one of chess''s great openings. Watch the main line, then play it yourself.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"},{"id":"watch","kind":"observe","coach":"Watch the Sicilian Defense unfold move by move.","fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","moves":["e2:e4","c7:c5","g1:f3","d7:d6","d2:d4","c5:d4","f3:d4","g8:f6","b1:c3"]}]',0);
